<template><view class="page"><view class="balance"><text>当前积分</text><text>{{ points }}</text><view class="balance-meta"><text>可用 {{ available }}</text><text>冻结 {{ locked }}</text></view></view><view v-if="expiring>0" class="expire-tip">有 {{ expiring }} 积分将在30天内到期，请优先在租车或服务预约时使用。</view><view v-if="loading" class="empty">积分明细读取中</view><view v-else-if="items.length" class="list"><view v-for="item in items" :key="item.id" class="item"><view><text class="name">{{ item.change_type_text }}</text><text class="time">{{ item.created_at }}</text><text v-if="item.description" class="desc">{{ item.description }}</text><text v-if="item.change_type==='earn'&&item.expired_at" class="expire-time">本笔剩余 {{ item.remaining_points }}，{{ item.expired_at }} 到期</text></view><view class="amount" :class="{minus:item.points<0}"><text>{{ item.points>0?'+':'' }}{{ item.points }}</text><text>余额 {{ item.balance_after }}</text></view></view></view><view v-else class="empty">暂无积分明细</view></view></template>
<script setup>import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import{getPoints}from'../../api/member';const points=ref(0),available=ref(0),locked=ref(0),expiring=ref(0),items=ref([]),loading=ref(true);const load=async()=>{loading.value=true;try{const r=await getPoints();points.value=r.data?.points||0;available.value=r.data?.available_points||0;locked.value=r.data?.locked_points||0;expiring.value=r.data?.expiring_points||0;items.value=r.data?.data||[]}catch(e){uni.showToast({title:e.msg||'读取失败',icon:'none'})}finally{loading.value=false}};onShow(load)</script>
<style scoped>.page{min-height:100vh;background:#f5f7fa}.balance{display:flex;flex-direction:column;padding:36rpx 32rpx;background:#1f2937;color:#fff}.balance>text:first-child{color:#cbd5e1;font-size:24rpx}.balance>text:nth-child(2){margin-top:8rpx;font-size:48rpx;font-weight:700}.balance-meta{display:flex;gap:28rpx;margin-top:16rpx}.balance-meta text{color:#dbeafe;font-size:22rpx;line-height:1.4}.expire-tip{margin:18rpx 32rpx;padding:18rpx;border-radius:6rpx;background:#fff7ed;color:#c2410c;font-size:22rpx;line-height:1.5}.list{margin-top:18rpx;background:#fff}.item{display:flex;justify-content:space-between;gap:20rpx;padding:24rpx 32rpx;border-bottom:1rpx solid #eef0f4}.name{display:block;color:#1f2937;font-size:27rpx}.time,.desc,.expire-time{display:block;margin-top:8rpx;color:#9ca3af;font-size:21rpx}.expire-time{color:#c2410c}.amount{display:flex;align-items:flex-end;flex-direction:column;color:#0f8e69;font-size:30rpx;font-weight:700}.amount.minus{color:#dc2626}.amount text:last-child{margin-top:8rpx;color:#9ca3af;font-size:20rpx;font-weight:400}.empty{padding:160rpx 0;color:#9ca3af;text-align:center;font-size:26rpx}</style>
